import os
import redis
from flask import Flask, request, jsonify

app = Flask(__name__)

# Secure connection to Redis using SSL
redis_client = redis.StrictRedis(
    host=os.getenv('REDIS_HOST', 'localhost'),
    port=int(os.getenv('REDIS_PORT', 6379)),
    password=os.getenv('REDIS_PASSWORD', None),
    ssl=True,
    ssl_cert_reqs=None
)

@app.route('/store', methods=['POST'])
def store_data():
    data = request.json
    session_token = data.get('session_token')
    api_key = data.get('api_key')

    if not session_token or not api_key:
        return jsonify({'error': 'Missing session token or API key'}), 400

    # Store session token with a TTL of 3600 seconds (1 hour)
    redis_client.setex(f'session:{session_token}', 3600, session_token)

    # Store API key with a TTL of 86400 seconds (24 hours)
    redis_client.setex(f'api_key:{api_key}', 86400, api_key)

    return jsonify({'message': 'Data stored successfully'}), 200

@app.route('/retrieve', methods=['GET'])
def retrieve_data():
    session_token = request.args.get('session_token')
    api_key = request.args.get('api_key')

    if session_token:
        stored_session = redis_client.get(f'session:{session_token}')
        if stored_session:
            return jsonify({'session_token': stored_session.decode('utf-8')}), 200
        return jsonify({'error': 'Session token not found'}), 404

    if api_key:
        stored_api_key = redis_client.get(f'api_key:{api_key}')
        if stored_api_key:
            return jsonify({'api_key': stored_api_key.decode('utf-8')}), 200
        return jsonify({'error': 'API key not found'}), 404

    return jsonify({'error': 'No data requested'}), 400

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)